
import { NextResponse } from 'next/server';
import { activateUserSubscriptionAdmin } from '@/lib/firebase/firebase-admin';

// This is the dedicated, secure server-side endpoint to grant paid access.
export async function POST(request: Request) {
  try {
    const { userId } = await request.json();

    if (!userId) {
      console.error('[API_GRANT_ACCESS] Error: userId is missing from the request.');
      return NextResponse.json({ error: 'User ID is required.' }, { status: 400 });
    }

    console.log(`[API_GRANT_ACCESS] Received request to grant access for UID: ${userId}`);
    await activateUserSubscriptionAdmin(userId);
    console.log(`[API_GRANT_ACCESS] Successfully granted access for UID: ${userId}`);

    return NextResponse.json({ success: true, message: `Access granted for user ${userId}.` }, { status: 200 });

  } catch (error) {
    console.error('[API_GRANT_ACCESS] Fatal error processing request:', error);
    const message = error instanceof Error ? error.message : 'An unknown server error occurred.';
    return NextResponse.json({ error: `Failed to grant access: ${message}` }, { status: 500 });
  }
}
